import type { CareerQuestion } from "./rrt-questions";

  export const imagingQuestionsBatch5: CareerQuestion[] = [
      {id:"img-b5-001",stem:"What is the effect of tube angulation on a radiographic image?",options:["Increased image density without distortion","Improved spatial resolution","Foreshortening or elongation of the anatomical structure","Reduced scatter radiation"],correctIndex:2,rationale:"Tube angulation causes shape distortion of the anatomical structure being imaged. Angling the tube along the length of a structure causes foreshortening, while angling across causes elongation.",difficulty:5,category:"Image Production",topic:"distortion"},
    {id:"img-b5-002",stem:"What is the relationship between photon energy and wavelength in the electromagnetic spectrum?",options:["Energy is inversely proportional to wavelength","Energy is directly proportional to wavelength","Energy and wavelength are unrelated","Energy equals wavelength squared"],correctIndex:0,rationale:"Photon energy and wavelength have an inverse relationship described by E = hf = hc/λ. Higher energy photons have shorter wavelengths. This is why increasing kVp produces higher-energy, more penetrating x-ray photons.",difficulty:5,category:"Physics",topic:"electromagnetic spectrum"},
    {id:"img-b5-003",stem:"What is the minimum lead equivalence required for thyroid shields used during fluoroscopy?",options:["0.5 mm Pb equivalent","0.1 mm Pb equivalent","3.0 mm Pb equivalent","1.5 mm Pb equivalent"],correctIndex:0,rationale:"Thyroid shields should provide at least 0.5 mm lead equivalence. The thyroid gland is radiosensitive and should be shielded during fluoroscopic procedures when it is in or near the radiation field.",difficulty:5,category:"Radiation Protection",topic:"thyroid shielding"},
    {id:"img-b5-004",stem:"A patient scheduled for an IVP has a creatinine level of 3.2 mg/dL. What should the technologist do?",options:["Use a lower concentration of contrast media","Notify the radiologist before proceeding with contrast administration","Switch to barium contrast instead","Proceed with the examination as scheduled"],correctIndex:1,rationale:"A creatinine level of 3.2 mg/dL indicates impaired renal function (normal is 0.6-1.2 mg/dL). The radiologist must be notified because iodinated contrast could worsen renal function and cause contrast-induced nephropathy.",difficulty:1,category:"Patient Care",topic:"contrast media"},
    {id:"img-b5-005",stem:"What is the function of the cathode focusing cup in an x-ray tube?",options:["To direct the electron stream toward a small area on the anode","To filter low-energy photons from the beam","To increase the tube current","To dissipate heat from the filament"],correctIndex:0,rationale:"The focusing cup is a negatively charged metal shroud around the filament that uses electrostatic repulsion to focus the electron stream into a narrow beam directed at the focal spot on the anode.",difficulty:1,category:"Equipment Operation",topic:"x-ray tube"},
    {id:"img-b5-006",stem:"For a PA projection of the chest, the central ray is directed to which level?",options:["The level of the iliac crest","The level of T4, at the sternal angle","The level of the xiphoid process","The level of T7, at the inferior angle of the scapulae"],correctIndex:3,rationale:"The central ray for a PA chest is directed to the midsagittal plane at the level of T7, approximately at the inferior angle of the scapulae. This ensures inclusion of the entire lung fields and costophrenic angles.",difficulty:1,category:"Procedures",topic:"chest radiography"},
    {id:"img-b5-007",stem:"Increasing kVp by 15% is approximately equivalent to:",options:["No change in exposure","Halving the mAs","Doubling the mAs","Tripling the mAs"],correctIndex:2,rationale:"The 15% rule states that increasing kVp by 15% approximately doubles the exposure to the image receptor, so the mAs can be reduced by half to maintain the same receptor exposure.",difficulty:1,category:"Image Production",topic:"technique selection"},
    {id:"img-b5-008",stem:"According to the inverse square law, if the source-to-image distance is changed from 40 to 80, what happens to beam intensity?",options:["It decreases to one-half of the original intensity","It decreases to one-quarter of the original intensity","It remains the same","It doubles"],correctIndex:1,rationale:"The inverse square law states that intensity is inversely proportional to the square of the distance. Doubling the distance (40 to 80) reduces intensity to 1/4 of the original value.",difficulty:1,category:"Physics",topic:"inverse square law"},
    {id:"img-b5-009",stem:"What is the recommended annual effective dose limit for radiation workers according to NCRP?",options:["50 mSv (5 rem)","100 mSv (10 rem)","10 mSv (1 rem)","500 mSv (50 rem)"],correctIndex:0,rationale:"The NCRP recommends an annual effective dose limit of 50 mSv (5 rem) for occupational radiation workers, with a cumulative lifetime limit of 10 mSv multiplied by the workers age in years.",difficulty:1,category:"Radiation Protection",topic:"dose limits"},
    {id:"img-b5-010",stem:"Which of the following is the most common adverse reaction to iodinated contrast media?",options:["Bronchospasm","Nausea and warmth sensation","Seizures","Cardiac arrest"],correctIndex:1,rationale:"The most common reactions to iodinated contrast are mild physiologic responses including nausea, warmth, and a metallic taste. These are not true allergic reactions and typically resolve without treatment.",difficulty:1,category:"Patient Care",topic:"contrast media"},
    {id:"img-b5-011",stem:"The anode heel effect is most pronounced when using:",options:["A large anode angle and long SID","A large focal spot","High mA settings","A small anode angle and short SID"],correctIndex:3,rationale:"The anode heel effect is more pronounced with smaller anode angles (which cause more self-absorption) and shorter SIDs (where the field size covers more of the angled anode surface).",difficulty:1,category:"Equipment Operation",topic:"heel effect"},
    {id:"img-b5-012",stem:"For the AP axial projection of the skull (Towne method), the central ray is angled:",options:["15 degrees cephalad","30 degrees caudad to the orbitomeatal line","Perpendicular to the film","45 degrees caudad"],correctIndex:1,rationale:"The Towne projection requires a 30-degree caudad angle to the OML (or 37 degrees to the IOML) to project the dorsum sellae and posterior clinoid processes into the foramen magnum.",difficulty:1,category:"Procedures",topic:"skull radiography"},
    {id:"img-b5-013",stem:"What is the primary controlling factor for radiographic density in a digital imaging system?",options:["kVp","Grid ratio","Focal spot size","mAs"],correctIndex:3,rationale:"In digital radiography, mAs remains the primary factor controlling the quantity of x-ray photons reaching the detector. While post-processing can adjust brightness, proper mAs ensures adequate signal-to-noise ratio.",difficulty:1,category:"Image Production",topic:"exposure factors"},
    {id:"img-b5-014",stem:"What factor has the greatest effect on the quantity of x-ray photons produced?",options:["Kilovoltage peak (kVp)","Source-to-image distance (SID)","Milliampere-seconds (mAs)","Focal spot size"],correctIndex:2,rationale:"The quantity (number) of x-ray photons produced is directly proportional to the mAs. Doubling the mAs doubles the number of photons. While kVp also affects quantity, mAs has the most direct linear relationship with photon output.",difficulty:1,category:"Physics",topic:"x-ray production factors"},
    {id:"img-b5-015",stem:"Which type of personal radiation monitoring device provides the most accurate long-term dose measurement?",options:["Pocket ionization chamber","Film badge","Geiger-Mueller counter","Optically stimulated luminescence (OSL) dosimeter"],correctIndex:3,rationale:"OSL dosimeters provide highly accurate cumulative dose readings over extended periods. They can be re-read multiple times, have a wide dose range, and are not affected by heat or humidity like film badges.",difficulty:1,category:"Radiation Protection",topic:"personnel monitoring"},
    {id:"img-b5-016",stem:"A patient in the radiology department suddenly becomes unresponsive and is not breathing. The first action should be:",options:["Move the patient to the waiting room","Administer oxygen via nasal cannula","Perform a radiographic examination to assess the situation","Activate the emergency response system and begin CPR"],correctIndex:3,rationale:"For an unresponsive patient who is not breathing, the immediate priority is to activate the emergency response system and begin CPR following BLS guidelines. Early defibrillation and advanced care improve survival.",difficulty:1,category:"Patient Care",topic:"medical emergencies"},
    {id:"img-b5-017",stem:"Which component of the x-ray imaging chain is responsible for converting light into an electrical signal in indirect DR?",options:["Amorphous silicon photodiode array","Film emulsion","Photostimulable phosphor plate","Intensifying screen"],correctIndex:0,rationale:"In indirect DR, the scintillator converts x-rays to light, and the amorphous silicon (a-Si) photodiode array then converts that light into electrical signals for digital processing.",difficulty:1,category:"Equipment Operation",topic:"DR system"},
    {id:"img-b5-018",stem:"Which projection best demonstrates the intercondylar fossa of the knee?",options:["Sunrise (tangential) projection","AP projection with the leg fully extended","Lateral projection","PA axial (Camp-Coventry) projection with 40-50 degree flexion"],correctIndex:3,rationale:"The Camp-Coventry projection (PA axial) with the knee flexed 40-50 degrees and the central ray angled 40 degrees caudad demonstrates the intercondylar fossa and the tibial eminence.",difficulty:1,category:"Procedures",topic:"skeletal imaging"},
    {id:"img-b5-019",stem:"A digital radiograph displays excessive noise (quantum mottle). Which technical adjustment would most effectively reduce this artifact?",options:["Increase the mAs","Decrease the kVp","Increase the SID","Use a higher grid ratio"],correctIndex:0,rationale:"Quantum mottle results from insufficient photon flux at the image receptor. Increasing mAs provides more photons to the detector, improving the signal-to-noise ratio and reducing the grainy appearance.",difficulty:2,category:"Image Production",topic:"noise"},
    {id:"img-b5-020",stem:"The unit of measurement for radiation absorbed dose in SI units is the:",options:["Sievert (Sv)","Gray (Gy)","Coulomb per kilogram (C/kg)","Roentgen (R)"],correctIndex:1,rationale:"The gray (Gy) is the SI unit of absorbed dose, representing 1 joule of energy absorbed per kilogram of tissue. It replaced the traditional unit rad (1 Gy = 100 rad).",difficulty:2,category:"Physics",topic:"radiation units"},
    {id:"img-b5-021",stem:"What is the minimum total filtration required for radiographic equipment operating above 70 kVp?",options:["5.0 mm aluminum equivalent","2.5 mm aluminum equivalent","1.0 mm aluminum equivalent","0.5 mm aluminum equivalent"],correctIndex:1,rationale:"A minimum of 2.5 mm aluminum equivalent total filtration is required for tubes operating above 70 kVp. This removes low-energy photons that would increase patient skin dose without contributing to image formation.",difficulty:2,category:"Radiation Protection",topic:"filtration"},
    {id:"img-b5-022",stem:"Which medication should be withheld for 48 hours after iodinated contrast administration in patients with diabetes?",options:["Insulin","Metformin","Glipizide","Acarbose"],correctIndex:1,rationale:"Metformin should be withheld for 48 hours after iodinated contrast administration because the combination can lead to lactic acidosis, particularly if the patient develops contrast-induced renal impairment.",difficulty:2,category:"Patient Care",topic:"pharmacology"},
    {id:"img-b5-023",stem:"The step-up transformer in the x-ray circuit functions to:",options:["Decrease voltage to heat the filament","Regulate mA output","Convert AC to DC current","Increase voltage from the autotransformer to kilovoltage levels"],correctIndex:3,rationale:"The step-up (high-voltage) transformer increases the relatively low voltage from the autotransformer to the kilovoltage range (25-150 kVp) needed to accelerate electrons across the x-ray tube.",difficulty:2,category:"Equipment Operation",topic:"transformer"},
    {id:"img-b5-024",stem:"For the AP open-mouth projection of C1-C2 (odontoid), the central ray enters through:",options:["The external auditory meatus","The center of the open mouth perpendicular to the image receptor","The glabella at 15 degrees caudad","The mentum at 30 degrees cephalad"],correctIndex:1,rationale:"The AP open-mouth (odontoid) projection requires the patient to open the mouth wide. The central ray enters perpendicular through the center of the open mouth to visualize C1-C2 and the dens without superimposition of the teeth or occiput.",difficulty:2,category:"Procedures",topic:"cervical spine imaging"},
    {id:"img-b5-025",stem:"Window level in digital imaging controls:",options:["The magnification factor","The brightness (density) of the displayed image","The contrast of the displayed image","The spatial resolution"],correctIndex:1,rationale:"Window level (center) determines which CT number or pixel value is displayed as middle gray. Adjusting the level shifts the brightness of the entire image lighter or darker.",difficulty:2,category:"Image Production",topic:"windowing"},
    {id:"img-b5-026",stem:"Compton scattering interaction is most likely to occur with:",options:["Very high energy photons interacting with the nucleus","Higher energy photons interacting with outer-shell electrons","Photons interacting with free electrons only","Lower energy photons interacting with inner-shell electrons"],correctIndex:1,rationale:"Compton scattering occurs when a photon interacts with a loosely bound outer-shell electron. It is the predominant interaction in soft tissue at diagnostic energies and is independent of atomic number.",difficulty:2,category:"Physics",topic:"photon interactions"},
    {id:"img-b5-027",stem:"The purpose of gonadal shielding in radiography is to:",options:["Improve image contrast","Reduce patient motion","Reduce the dose to reproductive organs from scatter and the primary beam","Increase the mAs"],correctIndex:2,rationale:"Gonadal shields (flat contact or shadow shields) reduce radiation dose to the reproductive organs, minimizing potential genetic effects. They should be used when gonads are within 5 cm of the primary field.",difficulty:2,category:"Radiation Protection",topic:"shielding"},
    {id:"img-b5-028",stem:"When a patient with a chest tube requires a portable chest radiograph, the technologist should:",options:["Disconnect the drainage system temporarily","Clamp the chest tube during exposure","Remove the chest tube for the examination","Include the entire chest tube and drainage system in the image"],correctIndex:3,rationale:"The entire chest tube and its drainage system should be visible on the radiograph so the physician can verify proper tube placement and check for complications such as pneumothorax or pleural effusion.",difficulty:2,category:"Patient Care",topic:"mobile radiography"},
    {id:"img-b5-029",stem:"Which type of x-ray generator produces the lowest voltage ripple?",options:["Three-phase 6-pulse generator","Three-phase 12-pulse generator","High-frequency generator","Single-phase generator"],correctIndex:2,rationale:"High-frequency generators produce less than 1% voltage ripple, providing the most consistent x-ray output. This results in higher average beam energy, shorter exposure times, and lower patient dose.",difficulty:2,category:"Equipment Operation",topic:"generator"},
    {id:"img-b5-030",stem:"The AP projection of the ankle requires the central ray to be directed to:",options:["The lateral malleolus","The talus","Midway between the malleoli","The medial malleolus"],correctIndex:2,rationale:"The central ray for an AP ankle is directed perpendicular to a point midway between the malleoli. The leg should be extended with the foot dorsiflexed to place the ankle at a 90-degree angle.",difficulty:2,category:"Procedures",topic:"extremity positioning"},
    {id:"img-b5-031",stem:"What is the relationship between grid ratio and patient dose?",options:["Higher grid ratios decrease patient dose","Grid ratio has no effect on patient dose","Higher grid ratios require increased technique, resulting in higher patient dose","Lower grid ratios require more mAs"],correctIndex:2,rationale:"Higher grid ratios absorb more scatter but also more primary radiation. The Bucky factor increases with grid ratio, requiring more mAs to maintain image density, which increases patient dose.",difficulty:2,category:"Image Production",topic:"grid usage"},
    {id:"img-b5-032",stem:"The half-value layer (HVL) of an x-ray beam is a measure of:",options:["Beam quantity","Beam quality (penetrating ability)","Patient dose","Image resolution"],correctIndex:1,rationale:"HVL represents the thickness of absorber needed to reduce beam intensity by 50%. A higher HVL indicates a more penetrating (harder) beam. It is the standard measure of beam quality.",difficulty:2,category:"Physics",topic:"half-value layer"},
    {id:"img-b5-033",stem:"A radiation worker receives a monthly dose report showing 4.5 mSv for the month. This value:",options:["Requires immediate medical evaluation","Is well within acceptable limits","Exceeds the annual limit","Warrants investigation as it approaches the recommended monthly limit"],correctIndex:3,rationale:"While the annual limit is 50 mSv, receiving 4.5 mSv in a single month is concerning because consistent monthly doses at this level would exceed the annual limit. The ALARA principle suggests investigation.",difficulty:2,category:"Radiation Protection",topic:"occupational dose"},
    {id:"img-b5-034",stem:"Before performing venipuncture for contrast injection, the technologist should verify:",options:["Only the requisition form","Only allergy history","Patient identity, allergy history, BUN/creatinine levels, and consent","Only patient identity"],correctIndex:2,rationale:"Safe contrast administration requires verification of patient identity (two identifiers), allergy history, renal function (BUN/creatinine), current medications, and informed consent documentation.",difficulty:3,category:"Patient Care",topic:"venipuncture"},
    {id:"img-b5-035",stem:"In computed radiography, the imaging plate stores the x-ray image as:",options:["A visible image on film","A latent image in trapped electrons within the photostimulable phosphor layer","A magnetic field pattern","An electrical charge in a capacitor"],correctIndex:1,rationale:"CR imaging plates contain europium-doped barium fluorohalide crystals that trap electrons in metastable energy states when exposed to x-rays, creating a latent image that is later released by laser stimulation.",difficulty:3,category:"Equipment Operation",topic:"CR system"},
    {id:"img-b5-036",stem:"The oblique projection that best demonstrates the left intervertebral foramina of the cervical spine is:",options:["RAO or LPO position","LAO or RPO position","AP open-mouth position","Left lateral position"],correctIndex:1,rationale:"The left intervertebral foramina are demonstrated in the LAO or RPO position (45-degree oblique). In cervical obliques, the foramina closest to the film in a PA oblique (or farthest in an AP oblique) are shown.",difficulty:3,category:"Procedures",topic:"spine imaging"},
    {id:"img-b5-037",stem:"Histogram analysis in digital radiography is used to:",options:["Measure patient dose","Calculate SID","Evaluate tube output","Determine the exposure level and optimize image display parameters"],correctIndex:3,rationale:"The histogram represents the distribution of pixel values in the image. The system analyzes this to determine exposure index and apply appropriate processing algorithms for optimal display.",difficulty:3,category:"Image Production",topic:"histogram analysis"},
    {id:"img-b5-038",stem:"What determines the maximum photon energy in the x-ray beam?",options:["The exposure time","The filtration","The mA setting","The peak kilovoltage (kVp) applied across the tube"],correctIndex:3,rationale:"The maximum photon energy equals the peak kilovoltage applied across the x-ray tube. An electron accelerated through 80 kVp can produce a photon with a maximum energy of 80 keV.",difficulty:3,category:"Physics",topic:"beam characteristics"},
    {id:"img-b5-039",stem:"Which of the following is the MOST effective method to reduce occupational radiation exposure during fluoroscopy?",options:["Wearing two film badges","Maximizing distance from the radiation source and using protective barriers","Using a slower frame rate only","Decreasing image brightness"],correctIndex:1,rationale:"Distance is the most effective protection method. Doubling the distance reduces exposure to one-quarter. Combined with shielding (lead apron, thyroid shield, protective curtains), exposure is minimized.",difficulty:3,category:"Radiation Protection",topic:"cardinal rules"},
    {id:"img-b5-040",stem:"A patient experiencing a vasovagal reaction to contrast media would most likely exhibit:",options:["Hypotension, bradycardia, and diaphoresis","Laryngeal edema","Hypertension and tachycardia","Urticaria and pruritus"],correctIndex:0,rationale:"Vasovagal reactions are characterized by hypotension, bradycardia, diaphoresis (sweating), pallor, and potentially syncope. Treatment includes leg elevation, IV fluids, and atropine if bradycardia persists.",difficulty:3,category:"Patient Care",topic:"contrast media"},
    {id:"img-b5-041",stem:"The rectification system in the x-ray circuit serves to:",options:["Increase the voltage applied to the tube","Control exposure time","Regulate filament heating","Convert alternating current to direct current for efficient x-ray production"],correctIndex:3,rationale:"Rectifiers convert AC to DC, ensuring electrons flow only from cathode to anode. Full-wave rectification uses both halves of the AC waveform, increasing x-ray production efficiency.",difficulty:3,category:"Equipment Operation",topic:"rectification"},
    {id:"img-b5-042",stem:"For a lateral projection of the facial bones, the interpupillary line should be:",options:["Perpendicular to the image receptor","At 30 degrees to the receptor","Parallel to the image receptor","At 45 degrees to the receptor"],correctIndex:0,rationale:"For a true lateral facial bones projection, the interpupillary line must be perpendicular to the image receptor and the midsagittal plane must be parallel to ensure no rotation of the skull.",difficulty:3,category:"Procedures",topic:"skull radiography"},
    {id:"img-b5-043",stem:"Increasing the field size in radiography will result in:",options:["Improved spatial resolution","No change in scatter radiation","Increased scatter radiation and decreased image contrast","Decreased scatter radiation"],correctIndex:2,rationale:"Increasing field size exposes more tissue volume, producing more scatter radiation through Compton interactions. Increased scatter reduces image contrast by adding fog density to the image.",difficulty:3,category:"Image Production",topic:"scatter control"},
    {id:"img-b5-044",stem:"Characteristic x-rays from a tungsten target are produced when the tube is operated at a minimum of:",options:["10 kVp","30 kVp","50 kVp","70 kVp, which exceeds the K-shell binding energy of tungsten"],correctIndex:3,rationale:"The K-shell binding energy of tungsten is 69.5 keV. The tube must operate at a minimum of 70 kVp for incident electrons to have enough energy to eject K-shell electrons and produce characteristic radiation.",difficulty:3,category:"Physics",topic:"characteristic radiation"},
    {id:"img-b5-045",stem:"The concept of cumulative effective dose for radiation workers is calculated as:",options:["25 mSv per decade of work","100 mSv total lifetime","50 mSv multiplied by years of employment","10 mSv multiplied by the workers age in years"],correctIndex:3,rationale:"The NCRP recommends a cumulative lifetime dose limit of 10 mSv times the workers age in years. For example, a 30-year-old worker should not have accumulated more than 300 mSv total.",difficulty:3,category:"Radiation Protection",topic:"dose limits"},
    {id:"img-b5-046",stem:"Normal adult body temperature measured orally is approximately:",options:["95.0 degrees Fahrenheit","100.4 degrees Fahrenheit","98.6 degrees Fahrenheit (37 degrees Celsius)","96.8 degrees Fahrenheit"],correctIndex:2,rationale:"Normal oral body temperature is 98.6 degrees Fahrenheit or 37 degrees Celsius. Temperatures above 100.4 degrees F indicate fever, which may affect the decision to proceed with certain imaging procedures.",difficulty:3,category:"Patient Care",topic:"vital signs"},
    {id:"img-b5-047",stem:"A flat panel detector in direct-conversion DR uses which material to convert x-rays directly to electrical signals?",options:["Barium fluorohalide","Cesium iodide","Amorphous selenium (a-Se)","Gadolinium oxysulfide"],correctIndex:2,rationale:"Amorphous selenium directly converts x-ray photons into electrical charges without an intermediate light conversion step, providing superior spatial resolution compared to indirect conversion systems.",difficulty:3,category:"Equipment Operation",topic:"DR system"},
    {id:"img-b5-048",stem:"The AP projection of the sacroiliac joints requires the central ray to be angled:",options:["30 degrees cephalad to the midpoint between the ASIS and symphysis pubis","15 degrees caudad","Perpendicular to the film","45 degrees cephalad"],correctIndex:0,rationale:"An AP axial projection with 30 degrees cephalad angulation opens the sacroiliac joints by projecting them free from the overlying sacrum. The CR enters midway between the ASIS and pubic symphysis.",difficulty:3,category:"Procedures",topic:"skeletal imaging"},
    {id:"img-b5-049",stem:"The deviation index (DI) in digital radiography indicates:",options:["The contrast resolution","How far the actual exposure deviates from the target exposure value","The spatial resolution of the system","The signal-to-noise ratio"],correctIndex:1,rationale:"The deviation index compares the actual exposure indicator value to the target value. A DI of zero indicates optimal exposure; positive values indicate overexposure and negative values indicate underexposure.",difficulty:3,category:"Image Production",topic:"exposure index"},
    {id:"img-b5-050",stem:"The electromagnetic spectrum lists x-rays as having wavelengths in which range?",options:["100 to 1000 nanometers","0.01 to 10 nanometers","1 to 100 micrometers","0.001 to 0.01 millimeters"],correctIndex:1,rationale:"Diagnostic x-rays have wavelengths ranging from approximately 0.01 to 10 nanometers. They fall between ultraviolet light and gamma rays on the electromagnetic spectrum, with shorter wavelengths having higher energy.",difficulty:3,category:"Physics",topic:"electromagnetic spectrum"},
    {id:"img-b5-051",stem:"Which type of secondary radiation barrier is designed to protect against leakage and scatter radiation?",options:["A lead apron worn by the patient","A barrier designed to stop the primary beam","The collimator housing","A barrier made of sufficient material to attenuate scatter and tube housing leakage radiation"],correctIndex:3,rationale:"Secondary barriers protect against leakage radiation from the tube housing and scatter from the patient and objects. They require less shielding than primary barriers because scatter and leakage are lower energy.",difficulty:3,category:"Radiation Protection",topic:"shielding"},
    {id:"img-b5-052",stem:"When positioning a patient for a decubitus chest radiograph, the patient should lie on the affected side to demonstrate:",options:["Pleural thickening","Free air in the affected hemithorax","Fluid levels in both lungs equally","Fluid layering in the dependent hemithorax"],correctIndex:3,rationale:"A decubitus position with the affected side down (dependent) allows fluid to layer along the dependent chest wall. With the affected side up, free air rises to demonstrate a pneumothorax.",difficulty:3,category:"Patient Care",topic:"patient assessment"},
    {id:"img-b5-053",stem:"What is the purpose of the space charge compensator (grid-controlled tube)?",options:["To increase the filament temperature","To provide precise control of exposure time by rapidly switching the tube current on and off","To rotate the anode","To filter the x-ray beam"],correctIndex:1,rationale:"Grid-controlled (grid-biased) tubes have a focusing cup that can be switched between negative bias (off) and neutral (on), allowing precise millisecond control of exposure time for applications like cineradiography.",difficulty:3,category:"Equipment Operation",topic:"x-ray tube"},
    {id:"img-b5-054",stem:"When performing a trauma cross-table lateral hip radiograph, the central ray is directed to:",options:["The greater trochanter","The iliac crest","The femoral neck, approximately 2.5 cm distal to the midpoint of a line between the ASIS and pubic symphysis","The ischial tuberosity"],correctIndex:2,rationale:"The central ray for a cross-table lateral hip is directed perpendicular to the femoral neck. The femoral neck is located approximately 2.5 cm distal to the midpoint between the ASIS and pubic symphysis.",difficulty:3,category:"Procedures",topic:"trauma radiography"},
    {id:"img-b5-055",stem:"What effect does decreasing the source-to-image distance (SID) have on image quality?",options:["Decreases magnification","Increases magnification and geometric unsharpness","Improves spatial resolution","Reduces distortion"],correctIndex:1,rationale:"Decreasing SID increases the beam divergence at the object level, resulting in greater magnification and more geometric unsharpness (penumbra). The standard SID of 40 is a compromise between magnification and tube output.",difficulty:3,category:"Image Production",topic:"magnification"},
    {id:"img-b5-056",stem:"The efficiency of x-ray production at diagnostic energies is approximately:",options:["Approximately 50 percent","Approximately 25 percent","Less than 1 percent, with over 99 percent converted to heat","Greater than 90 percent"],correctIndex:2,rationale:"At diagnostic energies, less than 1% of the kinetic energy of electrons striking the target is converted to x-ray photons. The remaining energy (over 99%) is converted to thermal energy in the anode.",difficulty:3,category:"Physics",topic:"x-ray production"},
    {id:"img-b5-057",stem:"The embryo/fetus dose limit for the entire gestation period is:",options:["5 mSv (0.5 rem) total, or 0.5 mSv per month","0.05 mSv total","No specific limit exists","50 mSv (5 rem) total"],correctIndex:0,rationale:"The NCRP recommends a maximum dose of 5 mSv (500 mrem) to the embryo/fetus for the entire gestation period, with a monthly limit of 0.5 mSv once pregnancy is declared.",difficulty:3,category:"Radiation Protection",topic:"embryo-fetal dose"},
    {id:"img-b5-058",stem:"Which pulse oximetry reading indicates the need for supplemental oxygen before proceeding with a radiographic examination?",options:["SpO2 of 100%","SpO2 of 95%","SpO2 below 90%","SpO2 of 98%"],correctIndex:2,rationale:"An SpO2 below 90% indicates significant hypoxemia requiring supplemental oxygen. Values of 95-100% are considered normal. The examination should be delayed until oxygenation is adequately addressed.",difficulty:3,category:"Patient Care",topic:"oxygen administration"},
    {id:"img-b5-059",stem:"Quality control testing of radiographic equipment should include collimator accuracy verification. The collimation must be accurate to within:",options:["No specific standard exists","2% of the SID","5% of the SID","10% of the SID"],correctIndex:1,rationale:"Federal regulations require that the x-ray field (collimated area) be accurate to within 2% of the SID in each dimension. At 100 cm SID, the total misalignment cannot exceed 2 cm.",difficulty:3,category:"Equipment Operation",topic:"quality control"},
    {id:"img-b5-060",stem:"Which projection of the elbow best demonstrates the coronoid process in profile?",options:["Lateral projection","AP oblique with medial (internal) rotation","AP projection","AP oblique with lateral (external) rotation"],correctIndex:1,rationale:"The AP oblique elbow with medial rotation (45 degrees) projects the coronoid process free from superimposition with the radial head, demonstrating it in profile.",difficulty:3,category:"Procedures",topic:"extremity positioning"},
    {id:"img-b5-061",stem:"In digital radiography, the speed class of the imaging system is analogous to:",options:["The dynamic range of the system","The processing algorithm used","The sensitivity of the detector to radiation exposure","The spatial resolution capability"],correctIndex:2,rationale:"Speed class in digital systems (200, 400, etc.) indicates detector sensitivity, similar to film-screen speed. Higher speed class means less radiation is needed for adequate exposure but may increase noise.",difficulty:3,category:"Image Production",topic:"receptor speed"},
    {id:"img-b5-062",stem:"Coherent (classical) scattering in diagnostic radiography:",options:["Only occurs above 1 MeV","Results in complete photon absorption","Occurs at low energies, changes photon direction without energy loss, and contributes to image fog","Is the predominant interaction in bone"],correctIndex:2,rationale:"Coherent (Rayleigh) scattering occurs predominantly at low photon energies. The photon changes direction without losing energy, contributing to image fog but not to patient dose.",difficulty:3,category:"Physics",topic:"photon interactions"},
    {id:"img-b5-063",stem:"A pregnant technologist should wear her second monitoring badge at:",options:["On the hand","On the ankle","Waist level under the lead apron to estimate fetal dose","Collar level over the lead apron"],correctIndex:2,rationale:"The fetal monitoring badge is worn at waist level under the lead apron to provide the best estimate of radiation dose to the embryo/fetus. The primary badge remains at collar level.",difficulty:3,category:"Radiation Protection",topic:"dosimetry"},
    {id:"img-b5-064",stem:"When caring for a patient with a tracheostomy during a radiographic examination, the technologist should:",options:["Ignore the tracheostomy unless complications arise","Remove the tracheostomy tube for the examination","Tape over the tracheostomy site","Keep suction equipment readily available and maintain the airway"],correctIndex:3,rationale:"Patients with tracheostomies require vigilant airway management. Suction equipment should be immediately available to clear secretions. The tube should never be removed by the technologist.",difficulty:3,category:"Patient Care",topic:"patient care"},
    {id:"img-b5-065",stem:"The purpose of automatic brightness control (ABC) in fluoroscopy is to:",options:["Increase patient dose","Control collimation","Decrease spatial resolution","Maintain consistent image brightness by adjusting kVp and mA automatically"],correctIndex:3,rationale:"ABC automatically adjusts technical factors (kVp, mA, or pulse width) during fluoroscopy to maintain consistent image brightness as the x-ray beam passes through different tissue thicknesses.",difficulty:3,category:"Equipment Operation",topic:"fluoroscopy"},
    {id:"img-b5-066",stem:"The Judet views of the pelvis are used to evaluate:",options:["Pelvic ring fractures","SI joint pathology","Hip dislocation","Acetabular fractures by demonstrating the anterior and posterior columns and rims"],correctIndex:3,rationale:"Judet (oblique) views of the pelvis demonstrate the acetabular columns and rims. The 45-degree RPO shows the right anterior column and left posterior column, and vice versa for LPO.",difficulty:3,category:"Procedures",topic:"skeletal imaging"},
    {id:"img-b5-067",stem:"The signal-to-noise ratio (SNR) in digital radiography is primarily determined by:",options:["The number of x-ray photons detected by the image receptor","The display monitor resolution","The kVp setting alone","The processing algorithm"],correctIndex:0,rationale:"SNR is fundamentally determined by the number of photons contributing to image formation. More photons (higher mAs) produce a stronger signal relative to electronic and quantum noise.",difficulty:3,category:"Image Production",topic:"noise"},
    {id:"img-b5-068",stem:"The photoelectric effect is most likely to occur when the photon energy is:",options:["Much higher than the binding energy","At exactly 1.02 MeV","Slightly above the binding energy of the inner-shell electron","Below the binding energy of any electron"],correctIndex:2,rationale:"Photoelectric absorption probability is highest when the photon energy is just above the K-shell binding energy of the absorber. At this energy, resonance absorption is maximized.",difficulty:3,category:"Physics",topic:"photon interactions"},
    {id:"img-b5-069",stem:"Which of the following actions would violate the ALARA principle?",options:["Using the smallest field size necessary","Routinely using the maximum field size for all examinations","Using the shortest exposure time practical","Shielding radiosensitive organs when possible"],correctIndex:1,rationale:"Using maximum field size for all examinations unnecessarily irradiates tissue outside the area of interest, increasing scatter radiation and patient dose. The field should be collimated to the anatomy of interest.",difficulty:3,category:"Radiation Protection",topic:"ALARA principle"},
    {id:"img-b5-070",stem:"A patient with a latex allergy requires a barium enema. The technologist should:",options:["Proceed with standard latex equipment","Use non-latex gloves and a non-latex balloon catheter tip","Use extra powder on the latex gloves","Cancel the examination"],correctIndex:1,rationale:"Patients with latex allergies require all latex products to be replaced with non-latex alternatives, including gloves, balloon-tipped catheters, and tourniquet materials. Latex exposure can cause anaphylaxis.",difficulty:3,category:"Patient Care",topic:"patient safety"},
    {id:"img-b5-071",stem:"What is the primary advantage of a high-frequency x-ray generator over a three-phase generator?",options:["Higher mA capability","Nearly constant voltage output with less than 1% ripple","Lower cost","Larger physical size"],correctIndex:1,rationale:"High-frequency generators convert incoming power to high-frequency AC (500-25,000 Hz) before rectification, producing nearly constant voltage with less than 1% ripple. This improves beam quality and reduces patient dose.",difficulty:3,category:"Equipment Operation",topic:"generator"},
    {id:"img-b5-072",stem:"For a PA oblique projection of the hand in a semi-pronated (fan lateral) position, the hand is rotated:",options:["90 degrees to a true lateral","45 degrees from the prone position with fingers fanned","15 degrees from prone","The hand remains in full pronation"],correctIndex:1,rationale:"The PA oblique hand requires 45-degree rotation from the prone position with fingers separated (fanned) to prevent superimposition. This demonstrates the phalanges and metacarpals without overlap.",difficulty:3,category:"Procedures",topic:"extremity positioning"},
    {id:"img-b5-073",stem:"The main purpose of using a compensating filter in radiography is to:",options:["Produce a more uniform exposure across an area of varying tissue thickness","Increase patient dose","Improve spatial resolution","Reduce scatter radiation"],correctIndex:0,rationale:"Compensating filters (wedge, trough, bowtie) equalize beam intensity across anatomical areas of varying thickness, such as the thoracic spine or foot, producing more uniform density across the image.",difficulty:3,category:"Image Production",topic:"technique selection"},
    {id:"img-b5-074",stem:"Attenuation of the x-ray beam as it passes through tissue is defined as:",options:["The conversion of x-rays to visible light","The reduction in beam intensity due to absorption and scatter","The acceleration of x-ray photons","The increase in beam energy"],correctIndex:1,rationale:"Attenuation refers to the overall reduction in x-ray beam intensity as photons are removed through photoelectric absorption and Compton scattering while passing through matter.",difficulty:4,category:"Physics",topic:"attenuation"},
    {id:"img-b5-075",stem:"The tabletop exposure rate limit during standard fluoroscopy must not exceed:",options:["88 mGy per minute (10 R per minute)","200 mGy per minute","No limit exists for standard fluoroscopy","50 mGy per minute"],correctIndex:0,rationale:"The FDA limits the tabletop exposure rate to 88 mGy/min (10 R/min) for standard fluoroscopy. High-level control fluoroscopy has a higher limit of 176 mGy/min (20 R/min) with additional safety features.",difficulty:4,category:"Radiation Protection",topic:"dose limits"},
    {id:"img-b5-076",stem:"When performing a modified barium swallow study, the speech-language pathologist collaborates with the technologist to evaluate:",options:["Small bowel obstruction","The phases of swallowing and detect aspiration or penetration","Colonic polyps","Gastric ulcers"],correctIndex:1,rationale:"A modified barium swallow (videofluoroscopic swallowing study) evaluates the oral, pharyngeal, and esophageal phases of swallowing. It identifies aspiration, penetration, and swallowing dysfunction to guide treatment.",difficulty:4,category:"Patient Care",topic:"patient assessment"},
    {id:"img-b5-077",stem:"The tube rating chart is used to determine:",options:["The image quality for a selected technique","The grid conversion factor","The patient dose for a given technique","Whether a selected combination of kVp, mA, and exposure time is safe for the x-ray tube"],correctIndex:3,rationale:"Tube rating charts display the safe operating limits for a specific x-ray tube. They show the maximum exposure time allowed for various combinations of kVp and mA to prevent anode damage from overheating.",difficulty:4,category:"Equipment Operation",topic:"tube rating"},
    {id:"img-b5-078",stem:"The parietoacanthial projection (Waters view) for the sinuses requires the OML to form what angle with the image receptor?",options:["25 degrees","45 degrees","15 degrees","37 degrees"],correctIndex:3,rationale:"The Waters projection requires the OML to form a 37-degree angle with the image receptor (chin elevated). This projects the petrous ridges below the maxillary sinuses for clear visualization.",difficulty:4,category:"Procedures",topic:"skull radiography"},
    {id:"img-b5-079",stem:"An exposure index that is too high (overexposure) in digital radiography typically results from:",options:["Excessive mAs for the anatomical part being imaged","Incorrect patient positioning","Grid misalignment","Insufficient kVp"],correctIndex:0,rationale:"Overexposure in digital radiography occurs when too many photons reach the detector, usually from excessive mAs. While the image can be post-processed to appear acceptable, the patient received unnecessary dose.",difficulty:4,category:"Image Production",topic:"exposure index"},
    {id:"img-b5-080",stem:"The Compton scattered photon has less energy than the incident photon because:",options:["No energy transfer occurs in Compton scattering","The photon is absorbed completely","Energy is transferred to the recoil electron during the interaction","The photon gains energy from the interaction"],correctIndex:2,rationale:"In Compton scattering, the incident photon transfers a portion of its energy to a loosely bound electron (recoil electron). The scattered photon retains the remaining energy and travels in a different direction.",difficulty:4,category:"Physics",topic:"photon interactions"},
    {id:"img-b5-081",stem:"Which of the following is considered a stochastic effect of radiation exposure?",options:["Cataracts","Hair loss","Skin erythema","Cancer induction"],correctIndex:3,rationale:"Cancer is a stochastic effect because its probability of occurrence increases with dose but its severity is independent of dose. Deterministic effects (erythema, cataracts, hair loss) have dose thresholds.",difficulty:4,category:"Radiation Protection",topic:"biological effects"},
    {id:"img-b5-082",stem:"Which patient assessment finding would require the technologist to contact the referring physician before performing an upper GI series?",options:["The patient has a dental bridge","The patient is wearing a necklace","The patient had breakfast 4 hours ago","Signs of bowel perforation such as rigid abdomen and rebound tenderness"],correctIndex:3,rationale:"Signs of bowel perforation (rigid abdomen, rebound tenderness, fever) require contacting the referring physician because barium contrast is contraindicated if perforation is suspected. Water-soluble contrast would be used instead.",difficulty:4,category:"Patient Care",topic:"patient assessment"},
    {id:"img-b5-083",stem:"What is the minimum source-to-skin distance (SSD) required for fixed fluoroscopic equipment?",options:["38 cm (15 in.)","50 cm (20 in.)","20 cm (8 in.)","30 cm (12 in.)"],correctIndex:0,rationale:"FDA regulations require a minimum SSD of 38 cm (15 in.) for fixed fluoroscopic equipment and 30 cm (12 in.) for mobile C-arm units to prevent excessive skin dose from close proximity to the source.",difficulty:4,category:"Equipment Operation",topic:"fluoroscopy"},
    {id:"img-b5-084",stem:"The AP projection of the sacrum requires the central ray to be angled:",options:["Perpendicular to the film","15 degrees cephalad to the midline at the level of the ASIS","30 degrees cephalad","15 degrees caudad"],correctIndex:1,rationale:"A 15-degree cephalad angle is used for the AP sacrum to project the sacrum free from foreshortening caused by the sacral curvature. The central ray enters at the level of a point midway between the ASIS and pubic symphysis.",difficulty:4,category:"Procedures",topic:"spine imaging"},
    {id:"img-b5-085",stem:"Using a grid with a ratio of 12:1 instead of 8:1 will result in:",options:["Less scatter cleanup and lower patient dose","Better spatial resolution","No change in scatter cleanup or patient dose","Greater scatter cleanup but a higher patient dose due to increased Bucky factor"],correctIndex:3,rationale:"Higher grid ratios provide superior scatter cleanup (improved contrast) but have higher Bucky factors, requiring increased mAs to maintain density. The 12:1 ratio has a Bucky factor of approximately 5 compared to 4 for 8:1.",difficulty:4,category:"Image Production",topic:"grid usage"},
    {id:"img-b5-086",stem:"The wave-particle duality of x-rays means that they exhibit properties of both:",options:["Electromagnetic waves and discrete particles (photons)","Magnetic fields and electric currents","Sound waves and light waves","Alpha particles and beta particles"],correctIndex:0,rationale:"X-rays demonstrate wave-particle duality. They behave as waves in phenomena like diffraction and interference, and as particles (photons) in interactions like the photoelectric effect and Compton scattering.",difficulty:4,category:"Physics",topic:"wave-particle duality"},
    {id:"img-b5-087",stem:"Lead equivalent aprons of 0.5 mm thickness attenuate approximately what percentage of scatter radiation at 80 kVp?",options:["Over 95%","Approximately 50%","Less than 25%","Approximately 75%"],correctIndex:0,rationale:"A 0.5 mm lead equivalent apron attenuates approximately 95-99% of scatter radiation at typical diagnostic energies (60-100 kVp). This provides adequate protection for most fluoroscopic procedures.",difficulty:4,category:"Radiation Protection",topic:"protective devices"},
    {id:"img-b5-088",stem:"A patient presenting to radiology with signs of shock (cool, clammy skin, rapid weak pulse) should receive what immediate intervention?",options:["Place the patient in a sitting position","Place the patient supine with legs elevated and notify the physician immediately","Continue with the scheduled examination","Administer oral contrast media"],correctIndex:1,rationale:"Signs of shock require immediate intervention: supine positioning with legs elevated to improve venous return, notification of the physician, and monitoring vital signs. The examination should be delayed.",difficulty:4,category:"Patient Care",topic:"medical emergencies"},
    {id:"img-b5-089",stem:"The primary function of the AEC backup timer is to:",options:["Calibrate the detector","Improve image quality","Increase the dynamic range","Prevent excessive patient exposure if the AEC fails to terminate the exposure"],correctIndex:3,rationale:"The backup timer is a safety mechanism that terminates the exposure after a preset maximum time (usually 150% of expected exposure) if the AEC fails, preventing overexposure of the patient.",difficulty:4,category:"Equipment Operation",topic:"AEC"},
    {id:"img-b5-090",stem:"For the AP axial projection of the clavicle, the central ray is angled:",options:["15-30 degrees caudad","Perpendicular to the film","45 degrees cephalad","15-30 degrees cephalad to the midshaft of the clavicle"],correctIndex:3,rationale:"The AP axial clavicle uses a 15-30 degree cephalad angle to project the clavicle above the ribs and scapula. A greater angle may be used for patients with a barrel chest.",difficulty:4,category:"Procedures",topic:"skeletal imaging"},
    {id:"img-b5-091",stem:"The unsharp masking algorithm in digital image processing is used to:",options:["Compress the image file size","Reduce image noise","Increase image brightness","Enhance edge contrast and improve the visibility of fine details"],correctIndex:3,rationale:"Unsharp masking creates an edge-enhanced image by subtracting a blurred version from the original, then adding the difference back. This amplifies high-frequency information (edges and detail) in the image.",difficulty:4,category:"Image Production",topic:"digital processing"},
    {id:"img-b5-092",stem:"The unit of radiation exposure in air (traditional units) is the:",options:["Roentgen (R)","Curie","Rad","Rem"],correctIndex:0,rationale:"The roentgen (R) measures ionization in air caused by x-ray or gamma radiation. It is defined as the amount of radiation that produces 2.58 x 10^-4 coulombs per kilogram of dry air.",difficulty:4,category:"Physics",topic:"radiation units"},
    {id:"img-b5-093",stem:"When collimation is increased (field size decreased), which of the following occurs?",options:["Patient dose increases","Image noise decreases","Spatial resolution decreases","Scatter radiation decreases and contrast improves"],correctIndex:3,rationale:"Tighter collimation reduces the volume of tissue irradiated, decreasing scatter production. Less scatter reaching the receptor improves contrast. Patient dose also decreases with smaller field sizes.",difficulty:4,category:"Radiation Protection",topic:"distance"},
    {id:"img-b5-094",stem:"Normal adult respiration rate is approximately:",options:["5-8 breaths per minute","25-35 breaths per minute","12-20 breaths per minute","40-50 breaths per minute"],correctIndex:2,rationale:"Normal adult respiration rate is 12-20 breaths per minute at rest. Rates above 20 (tachypnea) or below 12 (bradypnea) may indicate respiratory distress or other medical conditions.",difficulty:5,category:"Patient Care",topic:"vital signs"},
    {id:"img-b5-095",stem:"The image intensifier in fluoroscopy increases image brightness through three mechanisms:",options:["Minification gain, flux gain, and acceleration of electrons","Scatter reduction, beam hardening, and attenuation","Distance, time, and shielding","Magnification, filtration, and collimation"],correctIndex:0,rationale:"Image intensifier brightness gain equals minification gain (ratio of input to output phosphor areas) times flux gain (acceleration of electrons from photocathode to output phosphor by 25-35 kV potential).",difficulty:5,category:"Equipment Operation",topic:"fluoroscopy"},
    {id:"img-b5-096",stem:"The lateral decubitus position with the left side down is used to demonstrate:",options:["Mediastinal masses","Only pleural effusion","Only pneumothorax","Free air along the right lateral chest wall or fluid layering in the left hemithorax"],correctIndex:3,rationale:"In a left lateral decubitus position, free air rises to the right (up) side and can be seen along the right lateral chest wall. Fluid gravitates to the left (dependent) side and layers along the dependent chest wall.",difficulty:5,category:"Procedures",topic:"chest radiography"},
    {id:"img-b5-097",stem:"Detective quantum efficiency (DQE) measures:",options:["The processing speed of the system","The total dose received by the patient","The spatial resolution of the detector","The ability of an imaging system to convert x-ray input to a useful output signal"],correctIndex:3,rationale:"DQE is a comprehensive measure of detector performance that accounts for how efficiently the detector converts incident x-ray photons into a useful image signal while maintaining signal-to-noise ratio.",difficulty:5,category:"Image Production",topic:"digital processing"},
    {id:"img-b5-098",stem:"The target interaction that produces the continuous x-ray spectrum is:",options:["Photoelectric absorption","Characteristic radiation","Bremsstrahlung radiation","Compton scattering"],correctIndex:2,rationale:"Bremsstrahlung (braking) radiation produces a continuous spectrum of x-ray energies ranging from zero to the peak kilovoltage. It results from electron deceleration near target nuclei.",difficulty:5,category:"Physics",topic:"bremsstrahlung"},
    {id:"img-b5-099",stem:"Personal dosimeters should be exchanged and read at intervals not exceeding:",options:["Every five years","Monthly or quarterly depending on facility policy","Only when a dose is suspected","Annually"],correctIndex:1,rationale:"Personal dosimeters (OSL, TLD) should be exchanged monthly or quarterly as determined by facility policy and regulatory requirements. Regular monitoring ensures timely detection of excessive exposure.",difficulty:5,category:"Radiation Protection",topic:"personnel monitoring"},
    {id:"img-b5-100",stem:"When a contrast reaction occurs and the patient develops difficulty breathing with stridor, this indicates:",options:["A mild skin reaction","Laryngeal edema, which is a severe life-threatening reaction requiring immediate treatment","A vasovagal response","Normal contrast side effects"],correctIndex:1,rationale:"Stridor with dyspnea indicates laryngeal edema, a severe (anaphylactoid) reaction. This is life-threatening and requires immediate emergency treatment including epinephrine, airway management, and emergency medical response.",difficulty:5,category:"Patient Care",topic:"contrast media"}
    ];